    private final KafkaConsumer<String, String> consumer;
    private volatile boolean closed = false;

    public InventoryConsumer(String bootstrapServers, String groupId) {
        this.consumer = createKafkaConsumer(bootstrapServers, groupId);
    }

    private KafkaConsumer<String, String> createKafkaConsumer(String bootstrapServers, String groupId) {
        Properties props = new Properties();

        // Use ConsumerConfig constants instead of string literals
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.CLIENT_ID_CONFIG, "inventory-consumer-" + UUID.randomUUID());

        // Key and value deserializers
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);

        // Disable auto-commit to enable manual control via commitSync()
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);

        // Set auto offset reset policy
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        // Set max records per poll for batch processing
        props.put(ConsumerConfig.MAX_POLL_RECORDS_CONFIG, 100);

        return new KafkaConsumer<>(props);
    }

    /**
     * Starts consuming messages from the inventory-updates topic.
     * Processes messages idempotently and commits offsets after each batch.
     * Handles WakeupException for graceful shutdown.
     */
    public void run() {
        try {
            // Subscribe to the inventory-updates topic
            consumer.subscribe(Collections.singletonList("inventory-updates"));

            // Consumer loop using poll(Duration) API
            while (!closed) {
                try {
                    // Poll for records with a 1-second timeout
                    ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));

                    // Process each record in the batch
                    for (ConsumerRecord<String, String> record : records) {
                        processInventoryUpdate(record);
                    }

                    // Commit offsets after processing the batch
                    if (records.count() > 0) {
                        consumer.commitSync();
                    }
                } catch (WakeupException e) {
                    // WakeupException indicates the consumer is being shut down
                    // Perform final commit before exiting
                    consumer.commitSync();
                    break;
                }
            }
        } finally {
            consumer.close();
        }
    }

    /**
     * Process a single inventory update message idempotently.
     * This method should be implemented to handle the business logic
     * and ensure idempotent processing (i.e., can safely process the same
     * message multiple times without adverse effects).
     *
     * @param record The inventory update record to process
     */
    private void processInventoryUpdate(ConsumerRecord<String, String> record) {
        // Example processing logic
        String key = record.key();
        String value = record.value();

        // Idempotent processing: use key as unique identifier
        // Process the inventory update message
        System.out.println("Processing inventory update - Key: " + key + ", Value: " + value +
                ", Partition: " + record.partition() + ", Offset: " + record.offset());

        // In production, this would update a database with idempotency checks
        // (e.g., using the message key as an idempotency key)
    }

    /**
     * Gracefully shutdown the consumer.
     * This method can be called from a shutdown hook or another thread.
     */
    public void shutdown() {
        closed = true;
        consumer.wakeup();
    }

    public static void main(String[] args) {
        String bootstrapServers = "localhost:9092";
        String groupId = "inventory-consumer-group";

        if (args.length > 0) {
            bootstrapServers = args[0];
        }
        if (args.length > 1) {
            groupId = args[1];
        }

        InventoryConsumer inventoryConsumer = new InventoryConsumer(bootstrapServers, groupId);

        // Register shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down InventoryConsumer...");
            inventoryConsumer.shutdown();
        }));

        // Start consuming
        inventoryConsumer.run();
    }
}

